import React from 'react';

const Hero = () => {
  return (
    <section className="hero" id="home">
      <div className="glass-card">
        <img src="/assets/fotodeperfil.png" alt="Profile Picture" className="profile-pic" id="profile-pic" />
        <h1>Bem-Vindo ao Meu Portifólio Online!</h1>
        <span className="highlight">Desenvolvedor Full-stack | Designer | Gestor de Tráfego</span>
        <a href="#projects" className="cta-button">Veja meus trabalhos</a>
      </div>
    </section>
  );
};

export default Hero;
